   168→// --- SelectPopover ---
   169→
   170→type SelectPopoverOption = {
   171→  value: string;
   172→  label: React.ReactNode;
   173→};
   174→
   175→interface SelectPopoverProps {
   176→  value: string;
   177→  onValueChange: (value: string) => void;
   178→  options: SelectPopoverOption[];
   179→  placeholder?: string;
   180→  searchable?: boolean;
   181→  searchPlaceholder?: string;
   182→  className?: string;
   183→  disabled?: boolean;
   184→}
   185→
   186→const SelectPopover = ({
   187→  value,
   188→  onValueChange,
   189→  options,
   190→  placeholder = "Selecionar",
   191→  searchable = false,
   192→  searchPlaceholder = "Buscar...",
   193→  className,
   194→  disabled,
   195→}: SelectPopoverProps) => {
   196→  const [open, setOpen] = React.useState(false);
   197→  const [search, setSearch] = React.useState("");
   198→  const selected = options.find((o) => o.value === value);
   199→
   200→  const filteredOptions = searchable && search.trim()
   201→    ? options.filter((o) =>
   202→        String(o.label).toLowerCase().includes(search.toLowerCase())
   203→      )
   204→    : options;
   205→
   206→  const handleOpenChange = (next: boolean) => {
   207→    setOpen(next);
   208→    if (!next) setSearch("");
   209→  };
   210→
   211→  return (
   212→    <Popover open={open} onOpenChange={handleOpenChange}>
   213→      <PopoverTrigger asChild>
   214→        <button
   215→          type="button"
   216→          disabled={disabled}
   217→          className={cn(
   218→            "flex h-[40px] w-full items-center justify-between rounded-[12px] border border-input bg-background px-3 py-2 text-[13px] ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50",
   219→            className
   220→          )}
   221→        >
   222→          <span className={cn(!selected && "text-muted-foreground")}>
   223→            {selected ? selected.label : placeholder}
   224→          </span>
   225→          <ChevronDown className="h-4 w-4 opacity-50 flex-shrink-0" />
   226→        </button>
   227→      </PopoverTrigger>
   228→      <PopoverContent
   229→        className="p-1 w-[var(--radix-popover-trigger-width)] overflow-hidden"
   230→        align="start"
   231→        sideOffset={4}
   232→      >
   233→        {searchable && (
   234→          <div className="relative p-1 pb-1">
   235→            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground pointer-events-none" />
   236→            <Input
   237→              value={search}
   238→              onChange={(e) => setSearch(e.target.value)}
   239→              placeholder={searchPlaceholder}
   240→              className="pl-8 h-8 text-sm"
   241→              autoFocus
   242→            />
   243→          </div>
   244→        )}
   245→        <div className="max-h-56 overflow-y-auto">
   246→          {filteredOptions.length === 0 ? (
   247→            <p className="py-3 text-center text-sm text-muted-foreground">
   248→              Nenhum resultado encontrado.
   249→            </p>
   250→          ) : (
   251→            filteredOptions.map((option) => (
   252→              <button
   253→                key={option.value}
   254→                type="button"
   255→                onClick={() => {
   256→                  onValueChange(option.value);
   257→                  handleOpenChange(false);
   258→                }}
   259→                className={cn(
   260→                  "relative flex w-full cursor-default select-none items-center rounded-sm py-1.5 pl-8 pr-2 text-[13px] outline-none transition-colors hover:bg-accent hover:text-accent-foreground",
   261→                  value === option.value && "bg-accent text-accent-foreground"
   262→                )}
   263→              >
   264→                {value === option.value && (
   265→                  <span className="absolute left-2 flex h-3.5 w-3.5 items-center justify-center">
   266→                    <Check className="h-4 w-4" />
   267→                  </span>
   268→                )}
   269→                <span className="truncate">{option.label}</span>
   270→              </button>
   271→            ))
   272→          )}
   273→        </div>
   274→      </PopoverContent>
   275→    </Popover>
   276→  );
   277→};
   278→
   279→SelectPopover.displayName = "SelectPopover";
