   281→// --- MultiSelect ---
   282→
   283→type MultiSelectOption = {
   284→  value: string;
   285→  label: string;
   286→};
   287→
   288→interface MultiSelectProps {
   289→  values: string[];
   290→  onValuesChange: (values: string[]) => void;
   291→  options: MultiSelectOption[];
   292→  placeholder?: string;
   293→  searchable?: boolean;
   294→  searchPlaceholder?: string;
   295→  className?: string;
   296→  disabled?: boolean;
   297→}
   298→
   299→const MultiSelect = ({
   300→  values,
   301→  onValuesChange,
   302→  options,
   303→  placeholder = "Selecionar",
   304→  searchable = false,
   305→  searchPlaceholder = "Buscar...",
   306→  className,
   307→  disabled,
   308→}: MultiSelectProps) => {
   309→  const [open, setOpen] = React.useState(false);
   310→  const [search, setSearch] = React.useState("");
   311→
   312→  const filteredOptions = searchable && search.trim()
   313→    ? options.filter((o) =>
   314→        o.label.toLowerCase().includes(search.toLowerCase())
   315→      )
   316→    : options;
   317→
   318→  const handleOpenChange = (next: boolean) => {
   319→    setOpen(next);
   320→    if (!next) setSearch("");
   321→  };
   322→
   323→  const handleToggle = (value: string) => {
   324→    const next = values.includes(value)
   325→      ? values.filter((v) => v !== value)
   326→      : [...values, value];
   327→    onValuesChange(next);
   328→  };
   329→
   330→  const triggerLabel = values.length === 0
   331→    ? placeholder
   332→    : values.length === 1
   333→      ? options.find((o) => o.value === values[0])?.label ?? placeholder
   334→      : `${values.length} selecionados`;
   335→
   336→  return (
   337→    <Popover open={open} onOpenChange={handleOpenChange}>
   338→      <PopoverTrigger asChild>
   339→        <button
   340→          type="button"
   341→          disabled={disabled}
   342→          className={cn(
   343→            "flex h-[40px] w-full items-center justify-between rounded-[12px] border border-input bg-background px-3 py-2 text-[13px] ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50",
   344→            className
   345→          )}
   346→        >
   347→          <span className={cn("truncate", values.length === 0 && "text-muted-foreground")}>
   348→            {triggerLabel}
   349→          </span>
   350→          <ChevronDown className="h-4 w-4 opacity-50 flex-shrink-0 ml-2" />
   351→        </button>
   352→      </PopoverTrigger>
   353→      <PopoverContent
   354→        className="p-1 w-[var(--radix-popover-trigger-width)] overflow-hidden"
   355→        align="start"
   356→        sideOffset={4}
   357→      >
   358→        {searchable && (
   359→          <div className="relative p-1 pb-1">
   360→            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground pointer-events-none" />
   361→            <Input
   362→              value={search}
   363→              onChange={(e) => setSearch(e.target.value)}
   364→              placeholder={searchPlaceholder}
   365→              className="pl-8 h-8 text-sm"
   366→              autoFocus
   367→            />
   368→          </div>
   369→        )}
   370→        <div className="max-h-56 overflow-y-auto">
   371→          {filteredOptions.length === 0 ? (
   372→            <p className="py-3 text-center text-sm text-muted-foreground">
   373→              Nenhum resultado encontrado.
   374→            </p>
   375→          ) : (
   376→            filteredOptions.map((option) => {
   377→              const isSelected = values.includes(option.value);
   378→              return (
   379→                <button
   380→                  key={option.value}
   381→                  type="button"
   382→                  onClick={() => handleToggle(option.value)}
   383→                  className={cn(
   384→                    "relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 pl-3 pr-2 text-[13px] outline-none transition-colors hover:bg-accent hover:text-accent-foreground",
   385→                    isSelected && "bg-accent/50"
   386→                  )}
   387→                >
   388→                  <Checkbox checked={isSelected} className="pointer-events-none" />
   389→                  <span className="truncate">{option.label}</span>
   390→                </button>
   391→              );
   392→            })
   393→          )}
   394→        </div>
   395→        {values.length > 0 && (
   396→          <div className="border-t p-1 mt-1">
   397→            <button
   398→              type="button"
   399→              onClick={() => onValuesChange([])}
   400→              className="w-full text-center text-[12px] text-muted-foreground hover:text-foreground py-1 transition-colors"
   401→            >
   402→              Limpar seleção
   403→            </button>
   404→          </div>
   405→        )}
   406→      </PopoverContent>
   407→    </Popover>
   408→  );
   409→};
   410→
   411→MultiSelect.displayName = "MultiSelect";
   412→
